package moe.shizuku.manager.filemanager.saf

import android.content.Context
import android.net.Uri
import android.util.Base64
import android.webkit.JavascriptInterface
import android.webkit.WebView
import androidx.documentfile.provider.DocumentFile
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch
import org.json.JSONArray
import org.json.JSONObject
import java.io.BufferedReader
import java.io.InputStreamReader

class SdcardBridge(
    private val context: Context,
    private val webView: WebView,
    private val coroutineScope: CoroutineScope,
    private val requestStorageAccess: (String, String, String) -> Unit
) {

    private fun invokeCallback(callbackId: String, data: String) {
        // Evaluasi JavaScript di UI thread secara asinkron (resolve promise JS)
        val js = "javascript:if(window.executeCallback) { window.executeCallback('$callbackId', $data); }"
        webView.post {
            webView.evaluateJavascript(js, null)
        }
    }

    private fun invokeError(callbackId: String, message: String) {
        // Return object JSON dengan properti 'error' agar ditangkap block catch/reject di JS
        val errorJson = JSONObject().apply { put("error", message) }.toString()
        invokeCallback(callbackId, errorJson)
    }

    @JavascriptInterface
    fun read(uriString: String, successCallbackId: String, errorCallbackId: String) {
        coroutineScope.launch(Dispatchers.IO) {
            try {
                val uri = Uri.parse(uriString)
                context.contentResolver.openInputStream(uri)?.use { inputStream ->
                    val bytes = inputStream.readBytes()
                    // Mengirimkan binary via Base64 ke JS, nantinya JS bisa merubah ke ArrayBuffer
                    val base64 = Base64.encodeToString(bytes, Base64.NO_WRAP)
                    val result = JSONObject().apply { 
                        put("data", base64)
                        put("encoding", "base64") 
                    }.toString()
                    invokeCallback(successCallbackId, result)
                } ?: invokeError(errorCallbackId, "Cannot open input stream")
            } catch (e: Exception) {
                invokeError(errorCallbackId, e.message ?: "Unknown error")
            }
        }
    }

    @JavascriptInterface
    fun readAsText(uriString: String, encoding: String, successCallbackId: String, errorCallbackId: String) {
        coroutineScope.launch(Dispatchers.IO) {
            try {
                val uri = Uri.parse(uriString)
                context.contentResolver.openInputStream(uri)?.use { inputStream ->
                    val charsetName = if (encoding.isEmpty()) "UTF-8" else encoding
                    val text = BufferedReader(InputStreamReader(inputStream, charsetName)).readText()
                    // Mengirim String mentah dalam wadah JSON
                    val result = JSONObject().apply { put("text", text) }.toString()
                    invokeCallback(successCallbackId, result)
                } ?: invokeError(errorCallbackId, "Cannot open input stream")
            } catch (e: Exception) {
                invokeError(errorCallbackId, e.message ?: "Unknown error")
            }
        }
    }

    @JavascriptInterface
    fun writeText(uriString: String, content: String, encoding: String, successCallbackId: String, errorCallbackId: String) {
        coroutineScope.launch(Dispatchers.IO) {
            try {
                val uri = Uri.parse(uriString)
                // Mode "wt" berarti tulis dan truncate (timpa file)
                context.contentResolver.openOutputStream(uri, "wt")?.use { outputStream ->
                    val charsetName = if (encoding.isEmpty()) "UTF-8" else encoding
                    outputStream.write(content.toByteArray(charset(charsetName)))
                    invokeCallback(successCallbackId, "{}") // Berhasil, kembalikan objek kosong
                } ?: invokeError(errorCallbackId, "Cannot open output stream")
            } catch (e: Exception) {
                invokeError(errorCallbackId, e.message ?: "Unknown error")
            }
        }
    }

    @JavascriptInterface
    fun listDir(uriString: String, successCallbackId: String, errorCallbackId: String) {
        coroutineScope.launch(Dispatchers.IO) {
            try {
                val uri = Uri.parse(uriString)
                val docFile = DocumentFile.fromTreeUri(context, uri) ?: DocumentFile.fromSingleUri(context, uri)

                if (docFile != null && docFile.isDirectory) {
                    val files = docFile.listFiles()
                    val jsonArray = JSONArray()
                    for (file in files) {
                        val obj = JSONObject().apply {
                            put("name", file.name)
                            put("url", file.uri.toString())
                            put("isDirectory", file.isDirectory)
                            put("size", file.length())
                        }
                        jsonArray.put(obj)
                    }
                    invokeCallback(successCallbackId, jsonArray.toString())
                } else {
                    invokeError(errorCallbackId, "Not a directory or does not exist")
                }
            } catch (e: Exception) {
                invokeError(errorCallbackId, e.message ?: "Unknown error")
            }
        }
    }

    @JavascriptInterface
    fun delete(uriString: String, successCallbackId: String, errorCallbackId: String) {
        coroutineScope.launch(Dispatchers.IO) {
            try {
                val uri = Uri.parse(uriString)
                val docFile = DocumentFile.fromSingleUri(context, uri) ?: DocumentFile.fromTreeUri(context, uri)
                if (docFile != null && docFile.exists()) {
                    if (docFile.delete()) {
                        invokeCallback(successCallbackId, "{}")
                    } else {
                        invokeError(errorCallbackId, "Failed to delete")
                    }
                } else {
                    invokeError(errorCallbackId, "File not found")
                }
            } catch (e: Exception) {
                invokeError(errorCallbackId, e.message ?: "Unknown error")
            }
        }
    }

    @JavascriptInterface
    fun rename(uriString: String, newName: String, successCallbackId: String, errorCallbackId: String) {
        coroutineScope.launch(Dispatchers.IO) {
            try {
                val uri = Uri.parse(uriString)
                val docFile = DocumentFile.fromSingleUri(context, uri) ?: DocumentFile.fromTreeUri(context, uri)
                if (docFile != null && docFile.exists()) {
                    if (docFile.renameTo(newName)) {
                        invokeCallback(successCallbackId, "\"${docFile.uri}\"")
                    } else {
                        invokeError(errorCallbackId, "Failed to rename")
                    }
                } else {
                    invokeError(errorCallbackId, "File not found")
                }
            } catch (e: Exception) {
                invokeError(errorCallbackId, e.message ?: "Unknown error")
            }
        }
    }

    @JavascriptInterface
    fun stats(uriString: String, successCallbackId: String, errorCallbackId: String) {
        coroutineScope.launch(Dispatchers.IO) {
            try {
                val uri = Uri.parse(uriString)
                val docFile = DocumentFile.fromTreeUri(context, uri) ?: DocumentFile.fromSingleUri(context, uri)

                if (docFile != null && docFile.exists()) {
                    val obj = JSONObject().apply {
                        put("name", docFile.name)
                        put("url", docFile.uri.toString())
                        put("isDirectory", docFile.isDirectory)
                        put("isFile", docFile.isFile)
                        put("size", docFile.length())
                        put("canRead", docFile.canRead())
                        put("canWrite", docFile.canWrite())
                        put("modifiedDate", docFile.lastModified())
                        put("exists", true)
                    }
                    invokeCallback(successCallbackId, obj.toString())
                } else {
                    val obj = JSONObject().apply {
                        put("exists", false)
                    }
                    invokeCallback(successCallbackId, obj.toString())
                }
            } catch (e: Exception) {
                invokeError(errorCallbackId, e.message ?: "Unknown error")
            }
        }
    }

    @JavascriptInterface
    fun formatUri(uriString: String, successCallbackId: String, errorCallbackId: String) {
        // Just return the uri string for now
        invokeCallback(successCallbackId, "\"$uriString\"")
    }

    @JavascriptInterface
    fun createFile(parentUriString: String, filename: String, successCallbackId: String, errorCallbackId: String) {
        coroutineScope.launch(Dispatchers.IO) {
            try {
                val parentUri = Uri.parse(parentUriString)
                val parentDoc = DocumentFile.fromTreeUri(context, parentUri)
                if (parentDoc != null && parentDoc.isDirectory) {
                    // Try to guess mime type from extension or fallback to text/plain
                    val mimeType = "text/plain" 
                    val newFile = parentDoc.createFile(mimeType, filename)
                    if (newFile != null) {
                        invokeCallback(successCallbackId, "\"${newFile.uri}\"")
                    } else {
                        invokeError(errorCallbackId, "Failed to create file")
                    }
                } else {
                    invokeError(errorCallbackId, "Parent directory not found")
                }
            } catch (e: Exception) {
                invokeError(errorCallbackId, e.message ?: "Unknown error")
            }
        }
    }

    @JavascriptInterface
    fun createDir(parentUriString: String, dirname: String, successCallbackId: String, errorCallbackId: String) {
        coroutineScope.launch(Dispatchers.IO) {
            try {
                val parentUri = Uri.parse(parentUriString)
                val parentDoc = DocumentFile.fromTreeUri(context, parentUri)
                if (parentDoc != null && parentDoc.isDirectory) {
                    val newDir = parentDoc.createDirectory(dirname)
                    if (newDir != null) {
                        invokeCallback(successCallbackId, "\"${newDir.uri}\"")
                    } else {
                        invokeError(errorCallbackId, "Failed to create directory")
                    }
                } else {
                    invokeError(errorCallbackId, "Parent directory not found")
                }
            } catch (e: Exception) {
                invokeError(errorCallbackId, e.message ?: "Unknown error")
            }
        }
    }

    @JavascriptInterface
    fun listStorages(successCallbackId: String, errorCallbackId: String) {
        // Return an empty array for now since Acode usually manages this in localStorage
        invokeCallback(successCallbackId, "[]")
    }

    @JavascriptInterface
    fun getPath(uriString: String, filename: String, successCallbackId: String, errorCallbackId: String) {
        // Simple append for now
        invokeCallback(successCallbackId, "\"$uriString%2F$filename\"")
    }

    @JavascriptInterface
    fun write(uriString: String, dataBase64: String, successCallbackId: String, errorCallbackId: String) {
        coroutineScope.launch(Dispatchers.IO) {
            try {
                val uri = Uri.parse(uriString)
                context.contentResolver.openOutputStream(uri, "wt")?.use { outputStream ->
                    val bytes = Base64.decode(dataBase64, Base64.DEFAULT)
                    outputStream.write(bytes)
                    invokeCallback(successCallbackId, "{}")
                } ?: invokeError(errorCallbackId, "Cannot open output stream")
            } catch (e: Exception) {
                invokeError(errorCallbackId, e.message ?: "Unknown error")
            }
        }
    }

    @JavascriptInterface
    fun copy(srcUriString: String, destUriString: String, successCallbackId: String, errorCallbackId: String) {
        coroutineScope.launch(Dispatchers.IO) {
            try {
                val srcUri = Uri.parse(srcUriString)
                val destUri = Uri.parse(destUriString) // destination directory
                val srcDoc = DocumentFile.fromSingleUri(context, srcUri) ?: DocumentFile.fromTreeUri(context, srcUri)
                val destDoc = DocumentFile.fromTreeUri(context, destUri)

                if (srcDoc != null && destDoc != null && destDoc.isDirectory) {
                    val mimeType = srcDoc.type ?: "application/octet-stream"
                    val newFile = destDoc.createFile(mimeType, srcDoc.name ?: "copied_file")
                    if (newFile != null) {
                        context.contentResolver.openInputStream(srcDoc.uri)?.use { inputStream ->
                            context.contentResolver.openOutputStream(newFile.uri)?.use { outputStream ->
                                inputStream.copyTo(outputStream)
                            }
                        }
                        invokeCallback(successCallbackId, "\"${newFile.uri}\"")
                    } else {
                        invokeError(errorCallbackId, "Failed to create destination file")
                    }
                } else {
                    invokeError(errorCallbackId, "Source or destination invalid")
                }
            } catch (e: Exception) {
                invokeError(errorCallbackId, e.message ?: "Unknown error")
            }
        }
    }

    @JavascriptInterface
    fun move(srcUriString: String, destUriString: String, successCallbackId: String, errorCallbackId: String) {
        coroutineScope.launch(Dispatchers.IO) {
            try {
                // Since SAF doesn't have a direct 'move' across different providers, we do copy then delete
                val srcUri = Uri.parse(srcUriString)
                val destUri = Uri.parse(destUriString)
                val srcDoc = DocumentFile.fromSingleUri(context, srcUri) ?: DocumentFile.fromTreeUri(context, srcUri)
                val destDoc = DocumentFile.fromTreeUri(context, destUri)

                if (srcDoc != null && destDoc != null && destDoc.isDirectory) {
                    val mimeType = srcDoc.type ?: "application/octet-stream"
                    val newFile = destDoc.createFile(mimeType, srcDoc.name ?: "moved_file")
                    if (newFile != null) {
                        context.contentResolver.openInputStream(srcDoc.uri)?.use { inputStream ->
                            context.contentResolver.openOutputStream(newFile.uri)?.use { outputStream ->
                                inputStream.copyTo(outputStream)
                            }
                        }
                        srcDoc.delete() // delete original
                        invokeCallback(successCallbackId, "\"${newFile.uri}\"")
                    } else {
                        invokeError(errorCallbackId, "Failed to create destination file")
                    }
                } else {
                    invokeError(errorCallbackId, "Source or destination invalid")
                }
            } catch (e: Exception) {
                invokeError(errorCallbackId, e.message ?: "Unknown error")
            }
        }
    }

    @JavascriptInterface
    fun getStorageAccessPermission(uuid: String, successCallbackId: String, errorCallbackId: String) {
        // Melempar eksekusi Intent SAF ke layer UI (Activity/Compose) yang memiliki ActivityResultRegistry
        requestStorageAccess(uuid, successCallbackId, errorCallbackId)
    }
}
